import{_ as t,o as a,c as r,S as o}from"./chunks/framework.DZlzLDBr.js";const u=JSON.parse('{"title":"Study Sessions","description":"","frontmatter":{},"headers":[],"relativePath":"Study-Sessions.md","filePath":"Study-Sessions.md","lastUpdated":null}'),d={name:"Study-Sessions.md"};function s(n,e,i,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="study-sessions" tabindex="-1">Study Sessions <a class="header-anchor" href="#study-sessions" aria-label="Permalink to &quot;Study Sessions&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Study sessions are where you review cards.</p><p>Sprout uses FSRS to decide when cards are due.</p><h2 id="starting-a-session" tabindex="-1">Starting a session <a class="header-anchor" href="#starting-a-session" aria-label="Permalink to &quot;Starting a session&quot;">​</a></h2><p>You can start from:</p><ul><li><strong>Study page</strong> — open the deck tree, pick a scope, and start.</li><li><strong>Home page</strong> — start from recent or pinned decks.</li><li><strong>Deck widget (sidebar)</strong> — starts from the currently open file context: <ul><li>If the open file is a regular note, the session scope is that single note only.</li><li>If the open file is a folder note (a note which has the same name as its parent folder — for example if you are using the <a href="https://github.com/LostPaul/obsidian-folder-notes" target="_blank" rel="noreferrer">Folder Notes</a> plugin), the scope is all notes in that folder and includes any subfolders and their notes.</li></ul></li></ul><h2 id="study-scopes" tabindex="-1">Study scopes <a class="header-anchor" href="#study-scopes" aria-label="Permalink to &quot;Study scopes&quot;">​</a></h2><p>Choose a scope (the set of cards to study):</p><table tabindex="0"><thead><tr><th>Scope</th><th>Covers</th></tr></thead><tbody><tr><td><strong>Vault</strong></td><td>Every card in the vault</td></tr><tr><td><strong>Folder</strong></td><td>Cards in notes under a folder</td></tr><tr><td><strong>Note</strong></td><td>Cards in a single note</td></tr><tr><td><strong>Group</strong></td><td>Cards tagged with one or more groups</td></tr></tbody></table><h2 id="card-order" tabindex="-1">Card order <a class="header-anchor" href="#card-order" aria-label="Permalink to &quot;Card order&quot;">​</a></h2><p>Sprout queues cards in this order: <strong>learning → relearning → review → new</strong>.</p><p>Related siblings (for example cloze siblings and IO children) are spaced apart so they do not appear back-to-back.</p><h2 id="daily-limits" tabindex="-1">Daily limits <a class="header-anchor" href="#daily-limits" aria-label="Permalink to &quot;Daily limits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Effect</th></tr></thead><tbody><tr><td>Daily new limit</td><td>20</td><td>Max new cards introduced per scope per day</td></tr><tr><td>Daily review limit</td><td>200</td><td>Max due cards shown per scope per day</td></tr></tbody></table><p>Limits reset at midnight and are tracked separately per scope.</p><h2 id="answering-cards" tabindex="-1">Answering cards <a class="header-anchor" href="#answering-cards" aria-label="Permalink to &quot;Answering cards&quot;">​</a></h2><p>Press <strong>Space</strong> or <strong>Enter</strong> to reveal the answer, then grade recall. See <a href="./Grading">Grading</a>.</p><h2 id="practice-mode" tabindex="-1">Practice mode <a class="header-anchor" href="#practice-mode" aria-label="Permalink to &quot;Practice mode&quot;">​</a></h2><p>Practice mode shows cards that are <strong>not due yet</strong>.</p><p>Cards are sorted by closest due date first.</p><p>Grades in Practice mode do <strong>not</strong> change scheduling.</p><h2 id="timer" tabindex="-1">Timer <a class="header-anchor" href="#timer" aria-label="Permalink to &quot;Timer&quot;">​</a></h2><p>A session timer in the header shows elapsed time. Use play/pause controls to manage it.</p><h2 id="auto-advance" tabindex="-1">Auto-advance <a class="header-anchor" href="#auto-advance" aria-label="Permalink to &quot;Auto-advance&quot;">​</a></h2><p>If enabled in Settings, unanswered cards are auto-graded <strong>Again</strong> and advanced after a delay.</p><p>Allowed delay is 3 to 60 seconds (default 60). A countdown is shown.</p><h2 id="skip" tabindex="-1">Skip <a class="header-anchor" href="#skip" aria-label="Permalink to &quot;Skip&quot;">​</a></h2><p>Enable <strong>Skip</strong> in Settings → Study.</p><p>Skipping pushes the card back in the queue and does <strong>not</strong> change scheduling.</p><table tabindex="0"><thead><tr><th>Skip count</th><th>Behaviour</th></tr></thead><tbody><tr><td>1st</td><td>Card moves back in queue</td></tr><tr><td>2nd</td><td>Card moves further back</td></tr><tr><td>3rd</td><td>A <strong>&quot;Bury for today?&quot;</strong> prompt appears</td></tr></tbody></table><p>At that prompt: press <code>B</code> to bury, or <code>Escape</code> to dismiss.</p><h2 id="more-menu" tabindex="-1">More menu <a class="header-anchor" href="#more-menu" aria-label="Permalink to &quot;More menu&quot;">​</a></h2><p>Press <code>M</code> or tap the <strong>⋮</strong> button to open the More menu:</p><table tabindex="0"><thead><tr><th>Action</th><th>Shortcut</th><th>Description</th></tr></thead><tbody><tr><td>Bury</td><td><code>B</code></td><td>Postpone card until tomorrow (see <a href="./Burying-Cards">Burying Cards</a>)</td></tr><tr><td>Suspend</td><td><code>S</code></td><td>Remove card from future reviews (see <a href="./Suspending-Cards">Suspending Cards</a>)</td></tr><tr><td>Undo</td><td><code>U</code></td><td>Revert the previous rating (only available on the next card)</td></tr><tr><td>Open note</td><td><code>O</code></td><td>Jump to the source note</td></tr><tr><td>Edit</td><td><code>E</code></td><td>Open the inline card editor</td></tr></tbody></table><h2 id="zoom" tabindex="-1">Zoom <a class="header-anchor" href="#zoom" aria-label="Permalink to &quot;Zoom&quot;">​</a></h2><p>Click any image during a review to open it in a full-screen overlay. Click again or press <code>Escape</code> to close.</p><h2 id="time-tracking" tabindex="-1">Time tracking <a class="header-anchor" href="#time-tracking" aria-label="Permalink to &quot;Time tracking&quot;">​</a></h2><p>Sprout records time spent per card (capped at 5 minutes) for analytics.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Reminders">Reminders</a></li><li><a href="./Gatekeeper">Gatekeeper</a></li></ul>',42)])])}const g=t(d,[["render",s]]);export{u as __pageData,g as default};
